     * a different icon instead of the default {@link AppIcon}.
     *
     * @param images One or more images at different resolutions (16, 32, 48 … px).
     */
    public void setApplicationIcon(java.util.List<? extends Image> images) {
        setIconImages(images);
    }

    /**
     * Get the content panel where child forms can add their components
     * @return The main content panel
     */
    public ThemedPanel getContentPanel() {
        return contentPanel;
    }

    /**
     * Get the custom title bar for customization
     * @return The CustomTitleBar
     */
    public CustomTitleBar getTitleBar() {
        return titleBar;
    }

    /**
     * Get the slide-out menu for customization
     * @return The SlideOutMenu
     */
    public SlideOutMenu getMenu() {
        return titleBar.getSlideOutMenu();
    }

    /**
     * Set custom menu items (clears existing items)
     * @param menuItems Array of menu item definitions (text, action pairs)
     */
    public void setMenuItems(MenuItem... menuItems) {
        SlideOutMenu menu = getMenu();
        menu.clearMenuItems();
        for (MenuItem item : menuItems) {
            menu.addCustomMenuItem(item.text, item.action);
        }
    }

    /**
     * Add a single menu item
     * @param text Menu item text
     * @param action Action to perform when clicked
     */
    public void addMenuItem(String text, Runnable action) {
        getMenu().addCustomMenuItem(text, action);
    }

    /**
     * Update the window title
     * @param newTitle New title text
     */
    public void setWindowTitle(String newTitle) {
        setTitle(newTitle);
        titleBar.setTitle(newTitle);
    }

    /**
     * Helper class for menu item definition
     */
    public static class MenuItem {
        public final String text;
        public final Runnable action;

        public MenuItem(String text, Runnable action) {
            this.text = text;
            this.action = action;
        }
    }
}

package com.kalynx.serverlessreviewtool.theme.icons;

import java.awt.*;
import java.awt.geom.Ellipse2D;
import java.awt.geom.Line2D;
import java.awt.image.BufferedImage;
import java.util.List;

/**
 * AppIcon - Programmatically generated application icon for the Serverless Review Tool.
 *
 * Design:
 *   ┌──────────────────┐
 *   │  ▬▬▬▬▬▬▬▬        │   ← code line 1
 *   │  ▬▬▬▬▬▬▬▬▬▬▬▬▬   │   ← code line 2 (longer)
 *   │  ▬▬▬▬▬▬           │   ← code line 3 (short)
 *   │             ⊙     │   ← magnifying glass (accent)
 *   └──────────────────┘
 *
 * Rendered at 16, 32, 48, 64, 128 px for all platform icon slots.
 */
public class AppIcon {

    // Palette – fixed so the icon looks good on any desktop regardless of app theme
    private static final Color BG_TOP    = new Color(0x1A2744);   // deep navy
    private static final Color BG_BOT    = new Color(0x0D1B38);   // darker navy
    private static final Color LINE_1    = new Color(0xCDD9F5);   // light blue-white  (unchanged line)
    private static final Color LINE_2    = new Color(0x4ADDAB);   // teal-green        (added line)
    private static final Color LINE_3    = new Color(0xFF7A7A);   // coral-red         (removed line)
    private static final Color GLASS_RIM = new Color(0xFFFFFF);
    private static final Color GLASS_FILL= new Color(0x4A90E2, true);  // semi-transparent blue

    /** Returns a list of images at standard icon sizes suitable for {@code JFrame.setIconImages}. */
    public static List<Image> createIconImages() {
        return List.of(
            createIcon(16),
            createIcon(32),
            createIcon(48),
            createIcon(64),
            createIcon(128)
        );
    }

    /** Renders the icon at an arbitrary pixel size. */
    public static BufferedImage createIcon(int size) {
        BufferedImage img = new BufferedImage(size, size, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = img.createGraphics();
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING,      RenderingHints.VALUE_ANTIALIAS_ON);
        g.setRenderingHint(RenderingHints.KEY_STROKE_CONTROL,    RenderingHints.VALUE_STROKE_PURE);
        g.setRenderingHint(RenderingHints.KEY_RENDERING,         RenderingHints.VALUE_RENDER_QUALITY);

        // ── Background: vertical gradient, rounded square ──────────────────
        int arc = Math.max(3, size / 5);
        GradientPaint grad = new GradientPaint(0, 0, BG_TOP, 0, size, BG_BOT);
        g.setPaint(grad);
        g.fillRoundRect(0, 0, size, size, arc, arc);

        // ── Code lines ─────────────────────────────────────────────────────
        // Three horizontal bars in the upper-left region
        int mx  = (int)(size * 0.15);          // left margin
        int my  = (int)(size * 0.18);          // top margin for first line
        int lh  = (int)(size * 0.14);          // line height (spacing)
        int lth = Math.max(1, size / 18);      // line thickness

        int[] lineWidths = {
            (int)(size * 0.52),   // line 1 – medium  (unchanged, light)
            (int)(size * 0.68),   // line 2 – long    (added,     green)
            (int)(size * 0.38),   // line 3 – short   (removed,   red)
        };
        Color[] lineColors = { LINE_1, LINE_2, LINE_3 };

        g.setStroke(new BasicStroke(lth, BasicStroke.CAP_ROUND, BasicStroke.JOIN_ROUND));
        for (int i = 0; i < 3; i++) {
            int y = my + i * lh + lh / 2;
            g.setColor(lineColors[i]);
            g.draw(new Line2D.Float(mx, y, mx + lineWidths[i], y));
        }

        // ── Magnifying glass (bottom-right) ────────────────────────────────
        double glassR  = size * 0.20;          // lens radius
        double cx      = size * 0.72;          // lens centre x
        double cy      = size * 0.72;          // lens centre y
        double handleL = size * 0.16;          // handle length
        double handleA = Math.toRadians(45);   // handle angle (bottom-right)

        // Lens fill (translucent)
        g.setColor(new Color(GLASS_FILL.getRed(), GLASS_FILL.getGreen(), GLASS_FILL.getBlue(), 80));
        g.fill(new Ellipse2D.Double(cx - glassR, cy - glassR, glassR * 2, glassR * 2));

        // Lens rim
        float rimStroke = Math.max(1f, size / 22f);
        g.setStroke(new BasicStroke(rimStroke, BasicStroke.CAP_ROUND, BasicStroke.JOIN_ROUND));
        g.setColor(GLASS_RIM);
        g.draw(new Ellipse2D.Double(cx - glassR, cy - glassR, glassR * 2, glassR * 2));

        // Handle
        double hx1 = cx + Math.cos(handleA) * glassR;
        double hy1 = cy + Math.sin(handleA) * glassR;
        double hx2 = hx1 + Math.cos(handleA) * handleL;
        double hy2 = hy1 + Math.sin(handleA) * handleL;
        g.setStroke(new BasicStroke(rimStroke * 1.2f, BasicStroke.CAP_ROUND, BasicStroke.JOIN_ROUND));
        g.draw(new Line2D.Double(hx1, hy1, hx2, hy2));

        g.dispose();
        return img;
    }
}

package com.kalynx.serverlessreviewtool.theme.icons;

import java.awt.*;
import java.awt.geom.*;
import java.awt.image.BufferedImage;
import java.util.List;

/**
 * ThemeIcon - Generic icon for any ThemedFrame application.
 *
 * Design: a rounded square split diagonally top-left (dark) ↔ bottom-right (light),
 * with a glowing accent line along the split and a sun/moon pair either side —
 * immediately communicating "theme / light-dark switching".
 *
 *   ╭──────────────╮
 *   │ ◐  dark  ╲   │
 *   │       ╲  light │
 *   │        ╲  ◑  │
 *   ╰──────────────╯
 */
public class ThemeIcon {

    private static final Color DARK_BG   = new Color(0x1A2744);
    private static final Color LIGHT_BG  = new Color(0xEDF2FB);
    private static final Color ACCENT    = new Color(0x4A90E2);
    private static final Color DARK_FG   = new Color(0xCDD9F5);
    private static final Color LIGHT_FG  = new Color(0x2C3E6B);

    public static List<Image> createIconImages() {
        return List.of(
            createIcon(16),
            createIcon(32),
            createIcon(48),
            createIcon(64),
            createIcon(128)
        );
    }

    public static BufferedImage createIcon(int size) {
        BufferedImage img = new BufferedImage(size, size, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = img.createGraphics();
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING,   RenderingHints.VALUE_ANTIALIAS_ON);
        g.setRenderingHint(RenderingHints.KEY_RENDERING,      RenderingHints.VALUE_RENDER_QUALITY);
        g.setRenderingHint(RenderingHints.KEY_STROKE_CONTROL, RenderingHints.VALUE_STROKE_PURE);

        int arc = Math.max(3, size / 5);
        Shape clip = new RoundRectangle2D.Float(0, 0, size, size, arc, arc);
        g.setClip(clip);

        // ── Dark half (top-left triangle) ──────────────────────────────────
        g.setColor(DARK_BG);
        g.fill(new Polygon(
            new int[]{0, size, 0},
            new int[]{0, 0,    size},
            3
        ));

        // ── Light half (bottom-right triangle) ────────────────────────────
        g.setColor(LIGHT_BG);
        g.fill(new Polygon(
            new int[]{size, size, 0},
            new int[]{0,    size, size},
            3
        ));

        // ── Accent dividing line with glow ─────────────────────────────────
        float lineW = Math.max(1.5f, size / 16f);
        // Soft outer glow passes
        float[] glowWidths  = { lineW * 5, lineW * 3, lineW * 1.5f };
        int[]   glowAlphas  = { 30, 60, 120 };
        for (int i = 0; i < glowWidths.length; i++) {
            g.setColor(new Color(ACCENT.getRed(), ACCENT.getGreen(), ACCENT.getBlue(), glowAlphas[i]));
            g.setStroke(new BasicStroke(glowWidths[i], BasicStroke.CAP_BUTT, BasicStroke.JOIN_MITER));
            g.drawLine(size, 0, 0, size);
        }
        // Solid accent line
        g.setColor(ACCENT);
        g.setStroke(new BasicStroke(lineW, BasicStroke.CAP_BUTT, BasicStroke.JOIN_MITER));
        g.drawLine(size, 0, 0, size);

        g.setClip(null);

        // ── Moon symbol on dark side ───────────────────────────────────────
        double sym = size * 0.18;       // symbol radius
        double mx  = size * 0.28;
        double my  = size * 0.28;

        // Full circle
        g.setColor(DARK_FG);
        g.fill(new Ellipse2D.Double(mx - sym, my - sym, sym * 2, sym * 2));
        // Bite out to make crescent
        double bite = sym * 0.6;
        g.setColor(DARK_BG);
        g.fill(new Ellipse2D.Double(mx - sym * 0.4, my - sym, bite * 2, bite * 2));

        // ── Sun symbol on light side ───────────────────────────────────────
        double sx  = size * 0.72;
        double sy  = size * 0.72;
        double sr  = sym * 0.55;

        g.setColor(LIGHT_FG);
        g.fill(new Ellipse2D.Double(sx - sr, sy - sr, sr * 2, sr * 2));

        float rayW = Math.max(1f, (float) sym / 5f);
        g.setStroke(new BasicStroke(rayW, BasicStroke.CAP_ROUND, BasicStroke.JOIN_ROUND));
        for (int i = 0; i < 8; i++) {
            double angle   = Math.toRadians(i * 45);
            double inner   = sr + sym * 0.22;
            double outer   = inner + sym * 0.28;
            g.draw(new Line2D.Double(
                sx + Math.cos(angle) * inner, sy + Math.sin(angle) * inner,
                sx + Math.cos(angle) * outer,  sy + Math.sin(angle) * outer
            ));
        }

        g.dispose();
        return img;
    }
}

package com.kalynx.serverlessreviewtool.ui;

import com.kalynx.serverlessreviewtool.theme.components.ThemedFrame;
import com.kalynx.serverlessreviewtool.theme.components.ThemedPanel;

import javax.swing.*;
import java.awt.*;

/**
 * MainFrame - The main application window
 * Contains ReviewSelectionPanel by default with navigation to Settings and Help
 */
public class MainFrame extends ThemedFrame {

    private ReviewSelectionPanel reviewSelectionPanel;
    private ReviewPanel reviewPanel;
    private SettingsPanel settingsPanel;
    private HelpPanel helpPanel;
    private ThemedPanel currentPanel;

    public MainFrame() {
        super("Serverless Review Tool", 1000, 700);
        initializePanels();
        setupMenuItems();
        showReviewPanel();
    }

    /**
     * Initialize all panels
     */
    private void initializePanels() {
        reviewSelectionPanel = new ReviewSelectionPanel();
        reviewPanel = new ReviewPanel();
        settingsPanel = new SettingsPanel();
        helpPanel = new HelpPanel();
    }

    /**
     * Setup menu items for navigation
     */
    private void setupMenuItems() {
        setMenuItems(
            new MenuItem("Reviews", this::showReviewPanel),
            new MenuItem("Review Code", this::showCodeReviewPanel),
            new MenuItem("Settings", this::showSettingsPanel),
            new MenuItem("Help", this::showHelpPanel)
        );
    }

    /**
     * Show the Review Selection panel
     */
    private void showReviewPanel() {
        switchPanel(reviewSelectionPanel);
        setWindowTitle("Serverless Review Tool - Reviews");
    }

    /**
     * Show the Code Review panel
     */
    private void showCodeReviewPanel() {
        switchPanel(reviewPanel);
        setWindowTitle("Serverless Review Tool - Code Review");
    }

    /**
     * Show the Settings panel
     */
    private void showSettingsPanel() {
        switchPanel(settingsPanel);
        setWindowTitle("Serverless Review Tool - Settings");
    }

    /**
     * Show the Help panel
     */
    private void showHelpPanel() {
        switchPanel(helpPanel);
        setWindowTitle("Serverless Review Tool - Help");
    }

    /**
     * Switch the active panel in the content area
     */
    private void switchPanel(ThemedPanel newPanel) {
        if (currentPanel != null) {
            getContentPanel().remove(currentPanel);
        }
        currentPanel = newPanel;
        getContentPanel().add(currentPanel, BorderLayout.CENTER);
        getContentPanel().revalidate();
        getContentPanel().repaint();
    }

    /**
     * Main entry point for the application
     */
    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> {
            MainFrame frame = new MainFrame();
            frame.setVisible(true);
        });
    }
}

